import os, json
print('Files in /tmp:')
for f in os.listdir('/tmp'):
    if f.endswith('.json'):
        print(f'  {f} ({os.path.getsize(f"/tmp/{f}")} bytes)')
        # Try to load and see what it contains
        try:
            with open(f'/tmp/{f}', 'r') as file:
                data = json.load(file)
                print(f'    - {len(data)} records')
                if data:
                    print(f'    - Sample: {data[0]}')
        except:
            print(f'    - Could not load or parse')
        print()

