import json, os, re, math

# First, let's see what files are actually available
print("Files in /tmp directory:")
for f in sorted(os.listdir('/tmp')):
    if f.endswith('.json'):
        size = os.path.getsize(os.path.join('/tmp', f))
        print(f"  {f} ({size} bytes)")

# Now let's check the actual variable names that are available
all_vars = list(globals().keys())
print("\nAll variables starting with 'var':")
for var in sorted(all_vars):
    if var.startswith('var'):
        val = globals()[var]
        print(f"  {var}: {type(val)}")
        if isinstance(val, str) and len(val) < 200:
            print(f"    Value: {val}")
        elif isinstance(val, list) and len(val) > 0:
            print(f"    List with {len(val)} items")
        elif isinstance(val, dict) and len(val) > 0:
            print(f"    Dict with {len(val)} keys")

